commands.examples:
CREATE INDEX idx_email ON users (email);
CREATE UNIQUE INDEX idx_username ON users (username);
CREATE INDEX idx_name_city ON users (last_name, city);
CREATE FULLTEXT INDEX idx_content ON articles (title, body);
CREATE INDEX idx_price ON products (price DESC);

EXPLAIN SELECT * FROM users WHERE email = 'john@mail.com';
EXPLAIN FORMAT=JSON SELECT * FROM orders JOIN users ON orders.user_id = users.id;
EXPLAIN ANALYZE SELECT * FROM products WHERE price > 100;

-- Buat fulltext index dulu
ALTER TABLE articles ADD FULLTEXT idx_ft (title, body);

-- Natural language search
SELECT *, MATCH(title, body) AGAINST('mysql performance') AS score
FROM articles
WHERE MATCH(title, body) AGAINST('mysql performance')
ORDER BY score DESC;

-- Boolean mode
SELECT * FROM articles
WHERE MATCH(title, body) AGAINST('+mysql -oracle' IN BOOLEAN MODE);
